import crypto from 'node:crypto';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import cors from 'cors';
import dotenv from 'dotenv';
import express from 'express';
dotenv.config();
const app = express();
const port = Number(process.env.PORT || 4000);
const webhookTargetUrl = process.env.WEBHOOK_TARGET_URL || '';
const publicCallbackUrl = process.env.PUBLIC_CALLBACK_URL || '';
const publicWebhookUrl = process.env.PUBLIC_WEBHOOK_URL || '';
const webhookSecret = process.env.WEBHOOK_SECRET;
const callbackMessages = [];
const webhookRequests = [];
app.use(cors());
app.post('/webhook', express.raw({ type: '*/*', limit: '1mb' }), (req, res) => {
    const rawBody = Buffer.isBuffer(req.body) ? req.body.toString('utf8') : '';
    let body = rawBody;
    if (rawBody) {
        try {
            body = JSON.parse(rawBody);
        }
        catch {
            body = rawBody;
        }
    }
    else {
        body = null;
    }
    webhookRequests.unshift({
        id: crypto.randomUUID(),
        receivedAt: new Date().toISOString(),
        method: req.method,
        path: req.path,
        query: req.query,
        ip: req.ip || null,
        contentType: req.get('content-type') ?? null,
        headers: req.headers,
        body,
        rawBody,
        githubEvent: req.get('x-github-event') ?? null,
        githubDelivery: req.get('x-github-delivery') ?? null,
        hubSignature: req.get('x-hub-signature-256') ?? null
    });
    return res.status(200).json({ ok: true });
});
app.use(express.json());
app.get('/api/config', (_req, res) => {
    res.json({
        webhookTargetUrl,
        publicCallbackUrl,
        publicWebhookUrl
    });
});
app.get('/api/webhook-requests', (_req, res) => {
    res.json({ requests: webhookRequests });
});
app.post('/api/send-webhook', async (_req, res) => {
    const id = crypto.randomUUID();
    if (!webhookTargetUrl) {
        return res.status(500).json({
            id,
            status: 'failed',
            statusCode: null,
            error: 'WEBHOOK_TARGET_URL is not configured'
        });
    }
    if (!publicCallbackUrl) {
        return res.status(500).json({
            id,
            status: 'failed',
            statusCode: null,
            error: 'PUBLIC_CALLBACK_URL is not configured'
        });
    }
    const payload = {
        action: 'opened',
        delivery_id: id,
        installation: {
            id: 123456
        },
        repository: {
            name: 'demo-repo',
            full_name: 'demo-owner/demo-repo',
            owner: {
                login: 'demo-owner'
            }
        },
        pull_request: {
            number: 1,
            head: {
                sha: 'abc123'
            },
            title: 'Demo PR',
            body: 'This is a fake PR event generated by the simulator.'
        },
        callback_url: publicCallbackUrl
    };
    const rawBody = JSON.stringify(payload);
    const headers = {
        'Content-Type': 'application/json',
        'X-GitHub-Event': 'pull_request',
        'X-GitHub-Delivery': id,
        'User-Agent': 'GitHub-Hookshot-Simulator'
    };
    if (webhookSecret) {
        const digest = crypto.createHmac('sha256', webhookSecret).update(rawBody).digest('hex');
        headers['X-Hub-Signature-256'] = `sha256=${digest}`;
    }
    try {
        const response = await fetch(webhookTargetUrl, {
            method: 'POST',
            headers,
            body: rawBody,
            signal: AbortSignal.timeout(10000)
        });
        if (response.ok) {
            return res.json({
                id,
                status: 'accepted',
                statusCode: response.status
            });
        }
        return res.status(502).json({
            id,
            status: 'failed',
            statusCode: response.status,
            error: `Target returned status ${response.status}`
        });
    }
    catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return res.status(504).json({
            id,
            status: 'failed',
            statusCode: null,
            error: errorMessage
        });
    }
});
app.post('/comment', (req, res) => {
    const { id, message } = req.body;
    if (!id || !message) {
        return res.status(400).json({ error: 'id and message are required' });
    }
    callbackMessages.unshift({
        id,
        message,
        receivedAt: new Date().toISOString()
    });
    return res.status(200).json({ ok: true });
});
app.get('/api/comments', (_req, res) => {
    res.json({ comments: callbackMessages });
});
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const clientDistPath = path.resolve(__dirname, '../client-dist');
app.use(express.static(clientDistPath));
app.get('*', (req, res, next) => {
    if (req.path.startsWith('/api') || req.path === '/comment' || req.path === '/webhook') {
        return next();
    }
    return res.sendFile(path.join(clientDistPath, 'index.html'));
});
app.listen(port, () => {
    console.log(`Server running on http://localhost:${port}`);
});
